import{c as a,S as i,j as t,m as n}from"./chunks/framework.EDvvEH7Q.js";const u=JSON.parse('{"title":"","description":"","frontmatter":{"layout":"home","hero":{"name":"JuliaBUGS.jl","text":"Graph-based Probabilistic Programming","tagline":"A pure-Julia implementation of the BUGS language with Hamiltonian Monte Carlo, automatic differentiation, and a curated collection of classical examples.","image":{"src":"https://turinglang.org/assets/logo/turing-logo.svg","alt":"TuringLang"},"actions":[{"theme":"brand","text":"Get Started","link":"/example"},{"theme":"alt","text":"Browse Examples","link":"/examples/rats"},{"theme":"alt","text":"View on GitHub","link":"https://github.com/TuringLang/JuliaBUGS.jl"}]},"features":[{"title":"Compatible with BUGS","details":"Run existing BUGS programs without modification, alongside the modern @bugs and @model macros for Julia-native model definitions."},{"title":"Programmable Inference","details":"HMC via AdvancedHMC, independent MH, Gibbs, and full integration with the SciML and AbstractMCMC ecosystem."},{"title":"Classical Examples Included","details":"BUGSExamples ships with the Volume 1 corpus — model, data, inits, and reference posterior summaries — usable for benchmarks and tutorials."}]},"headers":[],"relativePath":"index.md","filePath":"index.md","lastUpdated":null}'),r={name:"index.md"};function l(o,e,s,d,p,c){return i(),t("div",null,[...e[0]||(e[0]=[n('<h2 id="What-is-JuliaBUGS?" tabindex="-1">What is JuliaBUGS? <a class="header-anchor" href="#What-is-JuliaBUGS?" aria-label="Permalink to &quot;What is JuliaBUGS? {#What-is-JuliaBUGS?}&quot;">​</a></h2><p>JuliaBUGS is a graph-based probabilistic programming framework inspired by the BUGS language. It compiles BUGS or <code>@bugs</code>/<code>@model</code> Julia syntax into a typed graph model that supports HMC and other samplers via <a href="https://github.com/TuringLang/AbstractMCMC.jl" target="_blank" rel="noreferrer">AbstractMCMC.jl</a>. BUGS traditionally refers to the software system, the language, or the inference algorithm; JuliaBUGS is a pure Julia implementation of the language — not a wrapper around the original system.</p><h2 id="Key-features" tabindex="-1">Key features <a class="header-anchor" href="#Key-features" aria-label="Permalink to &quot;Key features {#Key-features}&quot;">​</a></h2><ul><li><p>Compatibility with existing BUGS programs (parse and compile from the original syntax).</p></li><li><p>Three model-definition surfaces: the <code>@bugs(str)</code> parser, the <code>@bugs begin … end</code> macro, and <code>@model function … end</code> with full Julia scope.</p></li><li><p>Automatic differentiation through DifferentiationInterface (ForwardDiff / ReverseDiff / Enzyme / Mooncake).</p></li><li><p>Hamiltonian Monte Carlo via AdvancedHMC, independent MH, Gibbs sampling, and parallel/distributed chain support.</p></li><li><p>A curated collection of classical examples (<code>JuliaBUGS.BUGSExamples</code>) with multi-language source files (BUGS, <code>@bugs</code>, <code>@model</code>, Stan-pending), reference posterior summaries, and interactive DoodleBUGS graphs in the docs.</p></li></ul><h2 id="Understanding-the-BUGS-language" tabindex="-1">Understanding the BUGS language <a class="header-anchor" href="#Understanding-the-BUGS-language" aria-label="Permalink to &quot;Understanding the BUGS language {#Understanding-the-BUGS-language}&quot;">​</a></h2><p>The BUGS (Bayesian inference Using Gibbs Sampling) language is designed for specifying directed graphical models. Unlike imperative probabilistic programming languages such as Turing.jl or Pyro, BUGS focuses on declarative relationships between nodes in a graph. This graph-based approach offers several advantages:</p><ol><li><p><strong>Clarity</strong>: dependencies and relationships are visible in the model text itself.</p></li><li><p><strong>Transparency</strong>: conditional dependencies between variables are explicit, making model structure and assumptions auditable.</p></li><li><p><strong>Ease of development</strong>: graphical representations aid both model development and result interpretation.</p></li><li><p><strong>Efficient inference</strong>: the graph structure exposes conditional independencies that downstream samplers can exploit.</p></li></ol><p>JuliaBUGS combines the clarity and power of graphical models with the performance and flexibility of the Julia programming language.</p>',8)])])}const m=a(r,[["render",l]]);export{u as __pageData,m as default};
